// src/components/RepositoryDefaults.js
const RepositoryDefaults = {
  LICENSE: "MIT",
  VISIBILITY: "public",
  STATUS: "active",
  LIVE_DEMO: null,
  SCREENSHOTS: [],
  COVER_IMAGE: "/repo-covers/default.png", // placeholder copertina
  AVATAR: "/avatars/default-avatar.png",   // avatar owner di default
};

export default RepositoryDefaults;
